// ImmediateFinality Functional Handler Conformance Tests
//
// Auto-generated by TestGen from concept spec invariants.
// Validates StorageProgram construction, purity, variant coverage,
// read/write sets, interpreted execution, and invariant conformance.

import { describe, it, expect, beforeEach } from 'vitest';
import fc from 'fast-check';
import { immediateFinalityHandler } from '../../handlers/ts/app/governance/immediate-finality.handler.js';
import {
  classifyPurity,
  extractCompletionVariants,
  extractReadSet,
  extractWriteSet,
  extractPerformSet,
} from '../../runtime/storage-program.js';
import { interpret } from '../../runtime/interpreter.js';
import { createInMemoryStorage } from '../../runtime/adapters/storage.js';

describe('ImmediateFinality functional handler', () => {
  let storage: ReturnType<typeof createInMemoryStorage>;

  beforeEach(() => {
    storage = createInMemoryStorage();
  });

  describe('confirm', () => {
    it('builds a valid StorageProgram', () => {
      const program = immediateFinalityHandler.confirm({ operationRef: 'test-operationRef' });
      expect(program).toBeDefined();
      expect(program.instructions).toBeDefined();
      expect(Array.isArray(program.instructions)).toBe(true);
      expect(program.instructions.length).toBeGreaterThan(0);
    });

    it('has classifiable purity', () => {
      const program = immediateFinalityHandler.confirm({ operationRef: 'test-operationRef' });
      if (!program?.instructions) return; // skip non-StorageProgram handlers
      const purity = classifyPurity(program);
      expect(['pure', 'read-only', 'read-write']).toContain(purity);
    });

    it('covers all declared variants', () => {
      const program = immediateFinalityHandler.confirm({ operationRef: 'test-operationRef' });
      if (!program?.instructions) return; // skip non-StorageProgram handlers
      const variants = extractCompletionVariants(program);
      expect(variants).toContain('finalized');
    });

    it('declares read and write sets', () => {
      const program = immediateFinalityHandler.confirm({ operationRef: 'test-operationRef' });
      if (!program?.instructions) return; // skip non-StorageProgram handlers
      const reads = extractReadSet(program);
      const writes = extractWriteSet(program);
      const purity = classifyPurity(program);
      if (purity === 'read-only') {
        expect(reads.size).toBeGreaterThan(0);
      } else if (purity === 'read-write') {
        expect(writes.size).toBeGreaterThan(0);
      }
    });

    it('has trackable transport effects', () => {
      const program = immediateFinalityHandler.confirm({ operationRef: 'test-operationRef' });
      if (!program?.instructions) return; // skip non-StorageProgram handlers
      const effects = extractPerformSet(program);
      expect(effects).toBeDefined();
    });

    it('executes successfully', async () => {
      if (typeof immediateFinalityHandler.confirm !== 'function') return;
      const result = await interpret(immediateFinalityHandler.confirm({ operationRef: 'test-operationRef' }), storage);
      expect(result).toBeDefined();
      expect(result.variant).toBeDefined();
      expect(typeof result.variant).toBe('string');
    });

  });

  describe('invariant examples', () => {
    it("confirm-basic-flow", async () => {
      const storage = createInMemoryStorage();
      const confirmResult0 = await interpret(immediateFinalityHandler.confirm({ operationRef: {"type":"variable","name":"_"} }), storage);
      expect(confirmResult0.variant).toBe("finalized");
      const confirmation = confirmResult0.output["confirmation"];
    });

  });

  describe('state invariants (stateful PBT)', () => {
    it('always: valid-operationRef', async () => {
      await fc.assert(
        fc.asyncProperty(
          fc.array(
            fc.oneof(
              fc.record({ action: fc.constant('confirm'), input: fc.record({ operationRef: fc.string({ minLength: 1, maxLength: 20 }) }) }),
            ),
            { minLength: 1, maxLength: 5 },
          ),
          async (actionSequence) => {
            const storage = createInMemoryStorage();
            for (const step of actionSequence) {
              const actionFn = immediateFinalityHandler[step.action];
              if (typeof actionFn === 'function') {
                const program = actionFn.call(immediateFinalityHandler, step.input as Record<string, unknown>);
                const result = await interpret(program, storage);
                expect(result.variant).toBeDefined();
              }
            }
          },
        ),
        { numRuns: 50 },
      );
    });

    it('never: orphaned-confirmedAt', async () => {
      await fc.assert(
        fc.asyncProperty(
          fc.array(
            fc.oneof(
              fc.record({ action: fc.constant('confirm'), input: fc.record({ operationRef: fc.string({ minLength: 1, maxLength: 20 }) }) }),
            ),
            { minLength: 1, maxLength: 5 },
          ),
          async (actionSequence) => {
            const storage = createInMemoryStorage();
            for (const step of actionSequence) {
              const actionFn = immediateFinalityHandler[step.action];
              if (typeof actionFn === 'function') {
                const program = actionFn.call(immediateFinalityHandler, step.input as Record<string, unknown>);
                const result = await interpret(program, storage);
                expect(result.variant).toBeDefined();
                // Never: orphaned-confirmedAt
              }
            }
          },
        ),
        { numRuns: 50 },
      );
    });

  });

  describe('action contracts (PBT)', () => {
    it('confirm requires: ', async () => {
      const storage = createInMemoryStorage();
      const result = await interpret(immediateFinalityHandler.confirm({  }), storage);
      expect(['error', 'invalid', 'missing', 'notFound']).toContain(result.variant);
    });

    it('confirm ensures on finalized: ', async () => {
      await fc.assert(
        fc.asyncProperty(
          fc.record({ operationRef: fc.string({ minLength: 1, maxLength: 50 }) }),
          async (input) => {
            const storage = createInMemoryStorage();
            const program = immediateFinalityHandler.confirm(input as Record<string, unknown>);
            const result = await interpret(program, storage);
            fc.pre(result.variant === "finalized");
            expect(result.output).toBeDefined();
          },
        ),
        { numRuns: 100 },
      );
    });

  });

});
